@app.route("/items", methods=["POST"])
def create_item():
    payload: Dict[str, Any] = request.get_json(force=True, silent=False) or {}
    name = payload.get("name")
    if not name:
        return jsonify({"error": "name is required"}), 400

    with elasticapm.capture_span("db_insert_item", span_type="db", span_subtype="sqlite", span_action="query"):
        db = get_db()
        db.execute("INSERT INTO items (name, created_at) VALUES (?, ?)", (name, time.time()))
        db.commit()

    return jsonify({"created": True, "name": name}), 201


@app.route("/items", methods=["GET"])
def list_items():
    limit = int(request.args.get("limit", "50"))

    with elasticapm.capture_span("db_select_items", span_type="db", span_subtype="sqlite", span_action="query"):
        db = get_db()
        rows = db.execute(
            "SELECT id, name, created_at FROM items ORDER BY id DESC LIMIT ?",
            (limit,),
        ).fetchall()

    items = [{"id": r["id"], "name": r["name"], "created_at": r["created_at"]} for r in rows]
    return jsonify({"items": items, "count": len(items)})


